import { useState } from "react";

import API from "../services/api";

function TransactionForm({
  fetchDashboardData,
}) {

  const [type, setType] =
    useState("expense");

  const [category, setCategory] =
    useState("");

  const [amount, setAmount] =
    useState("");

  const [description,
    setDescription] = useState("");



  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      const token =
        localStorage.getItem("token");

      await API.post(
        "/transactions",
        {
          type,
          category,
          amount,
          description,
        },
        {
          headers: {
            Authorization:
              `Bearer ${token}`,
          },
        }
      );

      alert(
        "Transaction Added"
      );

      setCategory("");
      setAmount("");
      setDescription("");

      fetchDashboardData();

    } catch (error) {

      alert(
        "Add Transaction Failed"
      );

    }
  };



  return (

    <form
      onSubmit={handleSubmit}
      className="
      bg-white
      p-6
      rounded-xl
      shadow-lg
      mt-8
    "
    >

      <h2
        className="
        text-2xl
        font-bold
        mb-4
      "
      >
        Add Transaction
      </h2>





      <select
        value={type}
        onChange={(e) =>
          setType(e.target.value)
        }
        className="
        w-full
        border
        p-3
        rounded-lg
        mb-4
      "
      >

        <option value="expense">
          Expense
        </option>

        <option value="income">
          Income
        </option>

      </select>





      <input
        type="text"
        placeholder="Category"
        value={category}
        onChange={(e) =>
          setCategory(e.target.value)
        }
        className="
        w-full
        border
        p-3
        rounded-lg
        mb-4
      "
      />





      <input
        type="number"
        placeholder="Amount"
        value={amount}
        onChange={(e) =>
          setAmount(e.target.value)
        }
        className="
        w-full
        border
        p-3
        rounded-lg
        mb-4
      "
      />





      <input
        type="text"
        placeholder="Description"
        value={description}
        onChange={(e) =>
          setDescription(e.target.value)
        }
        className="
        w-full
        border
        p-3
        rounded-lg
        mb-4
      "
      />





      <button
        type="submit"
        className="
        bg-blue-600
        text-white
        px-6
        py-3
        rounded-lg
      "
      >
        Add Transaction
      </button>

    </form>
  );
}

export default TransactionForm;
